using Xunit;

// Disable test parallelization because NotificationService uses a static ConcurrentQueue.
// Parallel execution across test classes would cause cross-test contamination.
[assembly: CollectionBehavior(DisableTestParallelization = true)]

using ContosoUniversity.Data;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestHelpers
{
    /// <summary>
    /// Creates a fresh SchoolContext backed by an InMemory database with a unique name.
    /// Each call returns an isolated context to prevent cross-test contamination.
    /// </summary>
    public static SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains the static NotificationService queue to prevent cross-test contamination.
    /// Call this in test constructors and Dispose methods for tests that verify notification behavior.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }
}

using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    [Theory]
    [InlineData("Smith", "John", "Smith, John")]
    [InlineData("Doe", "Jane", "Doe, Jane")]
    [InlineData("O'Brien", "Mary", "O'Brien, Mary")]
    [InlineData("Li", "Wei", "Li, Wei")]
    public void FullName_ReturnsLastNameCommaFirstMidName(string lastName, string firstName, string expected)
    {
        // Arrange - using Student since Person is abstract
        var person = new Student
        {
            LastName = lastName,
            FirstMidName = firstName
        };

        // Act
        var result = person.FullName;

        // Assert
        Assert.Equal(expected, result);
    }

    [Fact]
    public void FullName_UsesCommaSpaceSeparator()
    {
        var person = new Student { LastName = "Alexander", FirstMidName = "Carson" };

        var result = person.FullName;

        Assert.Equal("Alexander, Carson", result);
        Assert.Contains(", ", result);
    }
}

using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models;

public class ErrorViewModelTests
{
    [Fact]
    public void ShowRequestId_WhenRequestIdIsSet_ReturnsTrue()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };
        Assert.True(model.ShowRequestId);
    }

    [Fact]
    public void ShowRequestId_WhenRequestIdIsNull_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = null };
        Assert.False(model.ShowRequestId);
    }

    [Fact]
    public void ShowRequestId_WhenRequestIdIsEmpty_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = "" };
        Assert.False(model.ShowRequestId);
    }

