    public void ShowRequestId_WhenRequestIdIsWhitespace_ReturnsTrue()
    {
        // string.IsNullOrEmpty does NOT consider whitespace as empty
        var model = new ErrorViewModel { RequestId = "   " };
        Assert.True(model.ShowRequestId);
    }
}

using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    private static IQueryable<int> CreateSource(int count)
    {
        return Enumerable.Range(1, count).AsQueryable();
    }

    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_LastPartialPage_ReturnsRemainingItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
    }

    [Theory]
    [InlineData(25, 10, 3)]
    [InlineData(20, 10, 2)]
    [InlineData(1, 10, 1)]
    [InlineData(10, 10, 1)]
    [InlineData(11, 10, 2)]
    [InlineData(0, 10, 0)]
    public void Create_CalculatesTotalPagesCorrectly(int totalItems, int pageSize, int expectedTotalPages)
    {
        var source = CreateSource(totalItems);

        var result = PaginatedList<int>.Create(source, 1, pageSize);

        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Fact]
    public void PageIndex_MatchesRequestedPage()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
    }

    [Fact]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_WhenMorePagesExist_ReturnsTrue()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        var source = CreateSource(5);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void HasPreviousPage_SinglePage_ReturnsFalse()
    {
        var source = CreateSource(5);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void Create_ExactlyOnePage_HasNoNavigation()
    {
        var source = CreateSource(10);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
        Assert.Equal(10, result.Count);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        TestHelpers.DrainNotificationQueue();
        _sut = new NotificationService();
    }

    public void Dispose()
    {
        _sut.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // --- SendNotification Tests ---

    [Fact]
    public void SendNotification_EnqueuesNotificationWithCorrectProperties()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("Student", result.EntityType);
        Assert.Equal("1", result.EntityId);
        Assert.Equal("CREATE", result.Operation);
        Assert.False(result.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesCreateMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("New Student 'John Doe' has been created", result.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesUpdateMessage()
    {
        _sut.SendNotification("Course", "101", "Mathematics", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("Course 'Mathematics' has been updated", result.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesDeleteMessage()
    {
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("Department 'Engineering' has been deleted", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedCreateMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("New Student (ID: 42) has been created", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedUpdateMessage()
    {
        _sut.SendNotification("Student", "99", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("Student (ID: 99) has been updated", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedDeleteMessage()
    {
        _sut.SendNotification("Instructor", "7", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("Instructor (ID: 7) has been deleted", result.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedByToProvidedUserName()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");

        var result = _sut.ReceiveNotification();

        Assert.Equal("admin", result.CreatedBy);
    }

    [Fact]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        var result = _sut.ReceiveNotification();

        Assert.Equal("System", result.CreatedBy);
    }

    [Fact]
    public void SendNotification_NoUserNameProvided_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.Equal("System", result.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);

        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var after = DateTime.Now.AddSeconds(1);
        var result = _sut.ReceiveNotification();
        Assert.InRange(result.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_SetsIsReadToFalse()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.False(result.IsRead);
    }

    // --- ReceiveNotification Tests ---

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);
        _sut.SendNotification("Student", "3", "Third", EntityOperation.CREATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.Equal("1", first.EntityId);
        Assert.Equal("2", second.EntityId);
        Assert.Equal("3", third.EntityId);
    }

    [Fact]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_AfterAllConsumed_ReturnsNull()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
        _sut.ReceiveNotification(); // consume it

        var result = _sut.ReceiveNotification();

        Assert.Null(result);
    }

    // --- Queue Cap Tests ---

    [Fact]
    public void QueueCap_WhenExceeds500_DropsOldestEntries()
    {
        // Enqueue 501 notifications
        for (int i = 1; i <= 501; i++)
        {
            _sut.SendNotification("Entity", i.ToString(), $"Item{i}", EntityOperation.CREATE);
        }

        // The first item should have been dropped due to the 500 cap
        var first = _sut.ReceiveNotification();
        Assert.Equal("2", first.EntityId); // Item 1 was dropped
    }

    // --- MarkAsRead Tests ---

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        var exception = Record.Exception(() => _sut.MarkAsRead(1));

        Assert.Null(exception);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_DoesNotThrow()
    {
        var exception = Record.Exception(() => _sut.MarkAsRead(999));

        Assert.Null(exception);
    }

    // --- Dispose Tests ---

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var svc = new NotificationService();

        var exception = Record.Exception(() => svc.Dispose());

        Assert.Null(exception);
    }

    // --- Two-Arg Overload Tests ---

    [Fact]
    public void SendNotification_TwoArgOverload_PassesNullDisplayName()
    {
        _sut.SendNotification("Student", "99", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        // Without display name, message uses ID-based format
        Assert.Equal("Student (ID: 99) has been updated", result.Message);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class BaseControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly TestableBaseController _controller;

    /// <summary>
    /// Concrete subclass to test the protected methods of BaseController.
    /// </summary>
    private class TestableBaseController : BaseController
    {
        public TestableBaseController(SchoolContext context) : base(context) { }

        public void InvokeSendNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void InvokeSendNotification(string entityType, string entityId, string displayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, displayName, operation);
        }
    }

    public BaseControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new TestableBaseController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    [Fact]
    public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
    {
        _controller.InvokeSendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Contains("John Doe", notification.Message);
    }

    [Fact]
    public void SendEntityNotification_WithoutDisplayName_EnqueuesNotificationWithIdFormat()
    {
        _controller.InvokeSendNotification("Department", "5", EntityOperation.DELETE);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Department", notification.EntityType);
        Assert.Contains("ID: 5", notification.Message);
    }

    [Fact]
    public void SendEntityNotification_UsesSystemAsDefaultUser()
    {
        _controller.InvokeSendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        using var svc = new NotificationService();
        var notification = svc.ReceiveNotification();

        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void Dispose_DisposesContextAndServiceWithoutException()
    {
        var context = TestHelpers.CreateContext();
        var controller = new TestableBaseController(context);

        var exception = Record.Exception(() => controller.Dispose());

        Assert.Null(exception);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Baker", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2019, 9, 1) },
            new Student { LastName = "Zheng", FirstMidName = "Li", EnrollmentDate = new DateTime(2022, 9, 1) }
        );
        _context.SaveChanges();
    }

    // ===================== Index Tests =====================

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();

        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Baker", model[2].LastName);
        Assert.Equal("Zheng", model[3].LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        SeedStudents();

        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Equal("Zheng", model[0].LastName);
        Assert.Equal("Baker", model[1].LastName);
        Assert.Equal("Alonso", model[2].LastName);
        Assert.Equal("Alexander", model[3].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();

        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Equal("Baker", model[0].LastName);       // 2019
        Assert.Equal("Alexander", model[1].LastName);   // 2020
        Assert.Equal("Alonso", model[2].LastName);      // 2021
        Assert.Equal("Zheng", model[3].LastName);       // 2022
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();

        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Equal("Zheng", model[0].LastName);       // 2022
        Assert.Equal("Alonso", model[1].LastName);      // 2021
        Assert.Equal("Alexander", model[2].LastName);   // 2020
        Assert.Equal("Baker", model[3].LastName);       // 2019
    }

    [Fact]
    public void Index_SearchByLastName_FiltersMatchingStudents()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "Alex", null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersMatchingStudents()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchNoMatch_ReturnsEmptyList()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Empty(model);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        SeedStudents();

        // When searchString is not null, page resets to 1
        var result = _controller.Index(null, "oldFilter", "newSearch", 5) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        SeedStudents();

        // When searchString is null, currentFilter is used
        var result = _controller.Index(null, "Alex", null, null) as ViewResult;
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SetsViewBagCurrentSort()
    {
        SeedStudents();

        _controller.Index("name_desc", null, null, null);

        Assert.Equal("name_desc", (string)_controller.ViewBag.CurrentSort);
    }

    [Fact]
    public void Index_DefaultSort_SetsNameSortParmToNameDesc()
    {
        SeedStudents();

        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", (string)_controller.ViewBag.NameSortParm);
    }

    [Fact]
    public void Index_NameDescSort_SetsNameSortParmToEmpty()
    {
        SeedStudents();

        _controller.Index("name_desc", null, null, null);

        Assert.Equal("", (string)_controller.ViewBag.NameSortParm);
    }

    [Fact]
    public void Index_DateSort_SetsDateSortParmToDateDesc()
    {
        SeedStudents();

        _controller.Index("Date", null, null, null);

        Assert.Equal("date_desc", (string)_controller.ViewBag.DateSortParm);
    }

    [Fact]
