using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // ===================== GetNotifications Tests =====================

    [Fact]
    public void GetNotifications_WhenQueueEmpty_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.True((bool)successProp.GetValue(value));
        Assert.Equal(0, (int)countProp.GetValue(value));
    }

    [Fact]
    public void GetNotifications_WhenQueueHasItems_ReturnsCorrectCount()
    {
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test1", EntityOperation.CREATE);
        svc.SendNotification("Student", "2", "Test2", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(2, (int)countProp.GetValue(value));
    }

    [Fact]
    public void GetNotifications_WhenQueueHasItems_ReturnsSuccessTrue()
    {
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp.GetValue(value));
    }

    [Fact]
    public void GetNotifications_LimitsResultsTo10()
    {
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Student", i.ToString(), $"Test{i}", EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(10, (int)countProp.GetValue(value));
    }

    [Fact]
    public void GetNotifications_ConsumesFromQueue_SecondCallGetsRemaining()
    {
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Student", i.ToString(), $"Test{i}", EntityOperation.CREATE);
        }

        // First call gets 10
        _controller.GetNotifications();

        // Second call gets remaining 5
        var result = _controller.GetNotifications();
        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(5, (int)countProp.GetValue(value));
    }

    [Fact]
    public void GetNotifications_ReturnsNotificationsList()
    {
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var notificationsProp = value.GetType().GetProperty("notifications");
        var notifications = notificationsProp.GetValue(value) as List<Notification>;
        Assert.NotNull(notifications);
        Assert.Single(notifications);
        Assert.Equal("Student", notifications[0].EntityType);
    }

    // ===================== MarkAsRead Tests =====================

    [Fact]
    public void MarkAsRead_ReturnsSuccessTrue()
    {
        var result = _controller.MarkAsRead(1);

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp.GetValue(value));
    }

    [Fact]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(999);

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp.GetValue(value));
    }

    // ===================== Index Tests =====================

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsType<ViewResult>(result);
    }
}

