+using ContosoUniversity.Data;
+using ContosoUniversity.Services;
+using Microsoft.EntityFrameworkCore;
+
+namespace ContosoUniversity.Tests.Helpers;
+
+public static class TestHelpers
+{
+    /// <summary>
+    /// Creates a fresh SchoolContext backed by an InMemory database with a unique name.
+    /// Each call returns an isolated context to prevent cross-test contamination.
+    /// </summary>
+    public static SchoolContext CreateContext(string dbName = null)
+    {
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
+            .Options;
+        return new SchoolContext(options);
+    }
+
+    /// <summary>
+    /// Drains the static NotificationService queue to prevent cross-test contamination.
+    /// Call this in test constructors and Dispose methods for tests that verify notification behavior.
+    /// </summary>
+    public static void DrainNotificationQueue()
+    {
+        using var svc = new NotificationService();
+        while (svc.ReceiveNotification() != null) { }
+    }
+}
