+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using ContosoUniversity.Tests.Helpers;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Services;
+
+public class NotificationServiceTests : IDisposable
+{
+    private readonly NotificationService _sut;
+
+    public NotificationServiceTests()
+    {
+        TestHelpers.DrainNotificationQueue();
+        _sut = new NotificationService();
+    }
+
+    public void Dispose()
+    {
+        _sut.Dispose();
+        TestHelpers.DrainNotificationQueue();
+    }
+
+    // --- SendNotification Tests ---
+
+    [Fact]
+    public void SendNotification_EnqueuesNotificationWithCorrectProperties()
+    {
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.NotNull(result);
+        Assert.Equal("Student", result.EntityType);
+        Assert.Equal("1", result.EntityId);
+        Assert.Equal("CREATE", result.Operation);
+        Assert.False(result.IsRead);
+    }
+
+    [Fact]
+    public void SendNotification_WithDisplayName_GeneratesCreateMessage()
+    {
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("New Student 'John Doe' has been created", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithDisplayName_GeneratesUpdateMessage()
+    {
+        _sut.SendNotification("Course", "101", "Mathematics", EntityOperation.UPDATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("Course 'Mathematics' has been updated", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithDisplayName_GeneratesDeleteMessage()
+    {
+        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("Department 'Engineering' has been deleted", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutDisplayName_GeneratesIdBasedCreateMessage()
+    {
+        _sut.SendNotification("Student", "42", EntityOperation.CREATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("New Student (ID: 42) has been created", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutDisplayName_GeneratesIdBasedUpdateMessage()
+    {
+        _sut.SendNotification("Student", "99", EntityOperation.UPDATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("Student (ID: 99) has been updated", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutDisplayName_GeneratesIdBasedDeleteMessage()
+    {
+        _sut.SendNotification("Instructor", "7", EntityOperation.DELETE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("Instructor (ID: 7) has been deleted", result.Message);
+    }
+
+    [Fact]
+    public void SendNotification_SetsCreatedByToProvidedUserName()
+    {
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("admin", result.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_NullUserName_DefaultsToSystem()
+    {
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("System", result.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_NoUserNameProvided_DefaultsToSystem()
+    {
+        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Equal("System", result.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_SetsCreatedAtToCurrentTime()
+    {
+        var before = DateTime.Now.AddSeconds(-1);
+
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+
+        var after = DateTime.Now.AddSeconds(1);
+        var result = _sut.ReceiveNotification();
+        Assert.InRange(result.CreatedAt, before, after);
+    }
+
+    [Fact]
+    public void SendNotification_SetsIsReadToFalse()
+    {
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.False(result.IsRead);
+    }
+
+    // --- ReceiveNotification Tests ---
+
+    [Fact]
+    public void ReceiveNotification_ReturnsInFIFOOrder()
+    {
+        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
+        _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);
+        _sut.SendNotification("Student", "3", "Third", EntityOperation.CREATE);
+
+        var first = _sut.ReceiveNotification();
+        var second = _sut.ReceiveNotification();
+        var third = _sut.ReceiveNotification();
+
+        Assert.Equal("1", first.EntityId);
+        Assert.Equal("2", second.EntityId);
+        Assert.Equal("3", third.EntityId);
+    }
+
+    [Fact]
+    public void ReceiveNotification_WhenEmpty_ReturnsNull()
+    {
+        var result = _sut.ReceiveNotification();
+
+        Assert.Null(result);
+    }
+
+    [Fact]
+    public void ReceiveNotification_AfterAllConsumed_ReturnsNull()
+    {
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+        _sut.ReceiveNotification(); // consume it
+
+        var result = _sut.ReceiveNotification();
+
+        Assert.Null(result);
+    }
+
+    // --- Queue Cap Tests ---
+
+    [Fact]
+    public void QueueCap_WhenExceeds500_DropsOldestEntries()
+    {
+        // Enqueue 501 notifications
+        for (int i = 1; i <= 501; i++)
+        {
+            _sut.SendNotification("Entity", i.ToString(), $"Item{i}", EntityOperation.CREATE);
+        }
+
+        // The first item should have been dropped due to the 500 cap
+        var first = _sut.ReceiveNotification();
+        Assert.Equal("2", first.EntityId); // Item 1 was dropped
+    }
+
+    // --- MarkAsRead Tests ---
+
+    [Fact]
+    public void MarkAsRead_DoesNotThrow()
+    {
+        // MarkAsRead is a no-op for in-memory implementation
+        var exception = Record.Exception(() => _sut.MarkAsRead(1));
+
+        Assert.Null(exception);
+    }
+
+    [Fact]
+    public void MarkAsRead_WithAnyId_DoesNotThrow()
+    {
+        var exception = Record.Exception(() => _sut.MarkAsRead(999));
+
+        Assert.Null(exception);
+    }
+
+    // --- Dispose Tests ---
+
+    [Fact]
+    public void Dispose_DoesNotThrow()
+    {
+        var svc = new NotificationService();
+
+        var exception = Record.Exception(() => svc.Dispose());
+
+        Assert.Null(exception);
+    }
+
+    // --- Two-Arg Overload Tests ---
+
+    [Fact]
+    public void SendNotification_TwoArgOverload_PassesNullDisplayName()
+    {
+        _sut.SendNotification("Student", "99", EntityOperation.UPDATE);
+
+        var result = _sut.ReceiveNotification();
+
+        // Without display name, message uses ID-based format
+        Assert.Equal("Student (ID: 99) has been updated", result.Message);
+    }
+}
+

