using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared helpers for creating in-memory SchoolContext instances and seed data.
/// </summary>
public static class TestHelpers
{
    public static SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedDepartmentsAndCourses(SchoolContext context)
    {
        var instructor = new Instructor { ID = 100, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID };
        context.Departments.Add(dept);
        context.SaveChanges();

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        context.SaveChanges();
    }

    public static void SeedInstructorsWithCourses(SchoolContext context)
    {
        SeedDepartmentsAndCourses(context);

        var instructor = context.Instructors.First();
        context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = instructor.ID, CourseID = 1050 },
            new CourseAssignment { InstructorID = instructor.ID, CourseID = 4022 }
        );

        context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instructor.ID, Location = "Smith 17" });
        context.SaveChanges();
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(21, result[0]);
    }

    [Theory]
    [InlineData(1, false, true)]   // first page
    [InlineData(2, true, true)]    // middle page
    [InlineData(3, true, false)]   // last page
    public void HasPreviousPage_HasNextPage_CorrectForPageIndex(int pageIndex, bool expectedPrev, bool expectedNext)
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex, pageSize: 10);

        Assert.Equal(expectedPrev, result.HasPreviousPage);
        Assert.Equal(expectedNext, result.HasNextPage);
    }

    [Fact]
    public void Create_SinglePage_NoNextNoPrevious()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }

    [Fact]
    public void Constructor_SetsProperties()
    {
        var items = new List<string> { "a", "b" };

        var list = new PaginatedList<string>(items, count: 20, pageIndex: 2, pageSize: 5);

        Assert.Equal(2, list.Count);
        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages);
    }
}

