using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    [Theory]
    [InlineData("Smith", "John", "Smith, John")]
    [InlineData("O'Brien", "Mary", "O'Brien, Mary")]
    [InlineData("Li", "Yan", "Li, Yan")]
    public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
    {
        var student = new Student { LastName = lastName, FirstMidName = firstName, EnrollmentDate = DateTime.Today };

        Assert.Equal(expected, student.FullName);
    }

    [Fact]
    public void FullName_WorksForInstructor()
    {
        var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane", HireDate = DateTime.Today };

        Assert.Equal("Doe, Jane", instructor.FullName);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class ErrorViewModelTests
{
    [Theory]
    [InlineData("abc123", true)]
    [InlineData("", false)]
    [InlineData(null, false)]
    public void ShowRequestId_ReturnsCorrectValue(string? requestId, bool expected)
    {
        var model = new ErrorViewModel { RequestId = requestId! };

        Assert.Equal(expected, model.ShowRequestId);
    }
}

